-- BOOTSTRAP-NAV-DESKTOP-CATALOG: the Desktop MAXINA navigation/routing catalog.
-- Generated by services/gateway/scripts/gen-desktop-nav-seed.ts from the desktop
-- web app route inventory (vitana-v1/src/App.tsx). Each entry reuses the screen’s
-- category/access/i18n and overrides the route with the real desktop path,
-- scoped to platform='desktop'. Admin/dev/role-gated routes + redirects excluded.
--
-- impact-allow-solo-migration: pure data seed into the existing nav_catalog /
-- nav_catalog_i18n tables (the runtime already reads them). Additive + idempotent.
-- 91 desktop screens.
BEGIN;

-- HOME.OVERVIEW
WITH up AS (
  INSERT INTO nav_catalog (screen_id, tenant_id, platform, route, category, access, anonymous_safe, priority, related_kb_topics, is_active)
  VALUES ('HOME.OVERVIEW', NULL, 'desktop', '/home', 'home', 'authenticated', FALSE, 0, '[]'::jsonb, TRUE)
  ON CONFLICT (screen_id, platform) WHERE tenant_id IS NULL
  DO UPDATE SET updated_at = now()
  RETURNING id
)
INSERT INTO nav_catalog_i18n (catalog_id, lang, title, description, when_to_visit)
SELECT up.id, v.lang, v.title, v.description, v.wtv
FROM up CROSS JOIN (VALUES
    ('en', 'Longevity News', 'Your home News Feed — the latest longevity news, research, and articles curated for you.', 'When the user wants news, longevity news, the latest news, the news feed, what is new in longevity, articles, research updates, or simply the home screen.'),
    ('de', 'Longevity News', 'Dein News-Feed zu Hause — aktuelle Longevity-Nachrichten, Forschung und Artikel, für dich kuratiert.', 'Wenn der Nutzer Nachrichten, Longevity-News, neueste Nachrichten, den News-Feed, Neuigkeiten zu Longevity, Artikel, Forschungs-Updates oder einfach die Startseite möchte.')
) AS v(lang, title, description, wtv)
ON CONFLICT (catalog_id, lang) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, when_to_visit = EXCLUDED.when_to_visit;

